  flashcards: [
    {front: "מהם שני השלבים של כל תהליך שבר?", back: "יצירת סדק (crack formation) והתפשטותו (propagation)."},
    {front: "מהם שני היתרונות של שבר גמיש על פני שבר שביר?", back: "מתריע מראש (עיוות פלסטי) ודורש אנרגיה רבה יותר להתרחשות."},
    {front: "מה ההבדל בין שבר טרנס-גרגירי לבין-גרגירי?", back: "טרנס-גרגירי — הסדק עובר דרך הגרגירים; בין-גרגירי — הסדק עובר לאורך גבולות הגרגיר."},
    {front: "מהו מקדם ריכוז מאמץ Kt?", back: "היחס σm/σ0=2√(a/ρt) — מדד להגברת מאמץ בקצה סדק."},
    {front: "מה ההבדל בין Kc ל-KIc?", back: "KIc הוא ערך Kc בתנאי מאמץ-מישורי (עובי דגימה גדול), ואינו תלוי עוד בעובי — הפרמטר המצוטט להנדסה."},
    {front: "מהם שלושת משתני העיצוב במכניקת שבר?", back: "מתיחות שבר (KIc), מאמץ מופעל (σ), וגודל פגם (a) — כל שניים קובעים את השלישי."},
    {front: "מה ההבדל בין קריטריון כניעה לדליפה-לפני-שבר?", back: "כניעה — הרכיב מתעוות לפני שבר; דליפה-לפני-שבר — סדק חודר את העובי המלא ומתגלה דרך דליפה, לפני התפשטות מהירה."},
    {front: "מה מודדות בדיקות Charpy ו-Izod?", back: "אנרגיית פגיעה (impact energy) — מדד איכותי-השוואתי, לא כמותי כמו KIc."},
    {front: "אילו חומרים אינם מציגים מעבר גמיש-שביר?", back: "מתכות FCC בחוזק נמוך ורוב מתכות HCP (נשארות קשיחות); חומרים בחוזק גבוה (נשארים שבריריים לאורך כל הטמפרטורות)."},
    {front: "אילו שני גורמים מורידים את טמפרטורת המעבר גמיש-שביר בפלדות?", back: "הקטנת גודל הגרגיר והורדת תכולת הפחמן."},
    {front: "מהו ההבדל בין גבול עייפות לחוזק עייפות?", back: "גבול עייפות — רמת מאמץ סף שמתחתיה אין כשל כלל; חוזק עייפות — רמת מאמץ הגורמת לכשל במספר מחזורים נתון, לחומרים ללא גבול עייפות."},
    {front: "מהם שלושת שלבי כשל העייפות?", back: "יזום סדק, התפשטות סדק, כשל סופי מהיר."},
    {front: "מה ההבדל בין סימני חוף לסטריאציות?", back: "סימני חוף מקרוסקopיים (הפרעות בהעמסה); סטריאציות מיקroskopיות (כל אחת = מחזור עומס בודד)."},
    {front: "מהן שתי דרכים לשפר עמידות עייפות של רכיב?", back: "שיפור עיצוב גיאומטרי (הימנעות מריכוזי מאמץ) וטיפולי משטח כמו ריקוע כדורי או הקשחת פנים."},
    {front: "מהם שלושת שלבי עקומת הזחילה?", back: "ראשוני (קצב יורד), משני/מצב יציב (קצב קבוע), שלישוני (קצב מואץ עד קריעה)."},
    {front: "מה קורה לקצב הזחילה ולאורך חיי הקריעה כשהטמפרטורה או המאמץ עולים?", back: "קצב הזחילה עולה ואורך חיי הקריעה יורד."},
    {front: "מדוע גרגיר גדול עדיף לעמידות זחילה, בניגוד לחוזק בטמפרטורת החדר?", back: "גרגיר גדול מפחית שטח גבול גרגיר זמין להחלקת גבולות גרגיר, המאיצה זחילה."},
    {front: "למה משמש פרמטר לארסון-מילר?", back: "לאקסטרפולציה של נתוני זחילה קצרי-טווח/טמפרטורה-גבוהה לחיזוי התנהגות ארוכת-טווח/טמפרטורה-נמוכה."}
  ],

