  quiz: [
    {q: "מהו ההבדל העיקרי בין סדק יציב לסדק בלתי-יציב?", options: ["סדק יציב לא מתפשט כלל", "סדק יציב מתנגד להתפשטות נוספת ללא עליית מאמץ; בלתי-יציב מתפשט ספונטנית", "סדק בלתי-יציב מופיע רק בחומרים גמישים", "אין הבדל מהותי ביניהם"], answer: 1, explain: "סדק יציב (שבר גמיש) דורש עלייה במאמץ כדי להמשיך ולהתפשט; סדק בלתי-יציב (שבר שביר), ברגע שהחל, ממשיך מעצמו.", hint: "חשבו על מה קורה אם לא מגדילים את הכוח המופעל.", level: "easy"},
    {q: "איזה פרופיל שבר אופייני למתכת גמישה מאוד, כמו זהב טהור בטמפרטורת החדר?", options: ["שבר גביע-וחרוט", "שבר שטוח ומאונך לחלוטין למאמץ", "צוואור עד לנקודה, עם כמעט 100% צמצום שטח", "שבר עם סימני שברון"], answer: 2, explain: "מתכות רכות מאוד מציגות צוואר קיצוני עד נקודה, ללא שבר גביע-וחרוט טיפוסי.", hint: "חשבו על המתכת הרכה ביותר שאתם מכירים.", level: "easy"},
    {q: "מהי מתיחות שבר במאמץ-מישורי (KIc)?", options: ["המאמץ המקסימלי שחומר סופג לפני כניעה", "פרמטר המודד עמידות חומר בפני שבר שביר בנוכחות סדק, ללא תלות בעובי הדגימה", "אנרגיית הפגיעה הנמדדת במבחן Charpy", "יחס בין חוזק קריעה לחוזק כניעה"], answer: 1, explain: "KIc היא תכונת חומר, נמדדת כאשר עובי הדגימה גדול מספיק כך שמתקיים תנאי מאמץ-מישורי.", hint: "זו לא תכונה תלוית-גיאומטריה של הדגימה עצמה, אלא תכונת חומר.", level: "easy"},
    {q: "מה מודדות בדיקות Charpy ו-Izod?", options: ["מתיחות שבר כמותית (KIc)", "אנרגיית פגיעה — מדד איכותי-השוואתי", "קצב זחילה במצב יציב", "גבול עייפות"], answer: 1, explain: "בדיקות פגיעה מספקות מדד איכותי בעיקר, שימושי להשוואה בין חומרים ולזיהוי מעבר גמיש-שביר — לא ערך עיצוב מדויק כמו KIc.", hint: "זהו מבחן פשוט ומהיר יחסית, לא מדויק כמו מבחן מתיחות שבר.", level: "easy"},
    {q: "עייפות מתרחשת תחת אילו תנאי מאמץ?", options: ["מאמץ סטטי בלבד", "מאמץ מחזורי/תנודתי, לרוב מתחת לחוזק הכניעה הסטטי", "מאמץ בטמפרטורה גבוהה בלבד", "מאמץ לחיצה בלבד"], answer: 1, explain: "עייפות מתרחשת תחת מאמצים דינמיים ותנודתיים, ולעיתים קרובות ברמת מאמץ נמוכה בהרבה מהחוזק הסטטי.", hint: "חשבו על גשר החווה עומסי תנועה חוזרים ונשנים.", level: "easy"},
    {q: "מה ההבדל בין גבול עייפות לחוזק עייפות?", options: ["אין הבדל, מונחים זהים", "גבול עייפות — סף שמתחתיו אין כשל כלל; חוזק עייפות — מאמץ הגורם לכשל במספר מחזורים נתון", "גבול עייפות רלוונטי רק לפולימרים", "חוזק עייפות תמיד גבוה מגבול עייפות"], answer: 1, explain: "גבול עייפות מאפיין סגסוגות פרוכתיות/טיטניום (עקומה אופקית); חוזק עייפות מאפיין סגסוגות ללא גבול עייפות אמיתי, כמו אלומיניום.", hint: "אחד מהמונחים מתאר סף אבסולוטי; השני תלוי במספר מחזורים ספציפי.", level: "easy"},
    {q: "בקצה סדק פנימי באורך a=4×10⁻2 מ״מ ורדיוס עקמומיות ρt=5×10⁻4 מ״מ, תחת מאמץ נומינלי σ0=100 MPa, מהו מקדם ריכוז המאמץ Kt?", options: ["≈4.0", "≈8.9", "≈17.9", "≈80"], answer: 2, explain: "Kt=2√(a/ρt)=2√(80)=2×8.944≈17.9. שימו לב: 80 הוא היחס a/ρt עצמו, לא Kt.", hint: "חשבו קודם את היחס a/ρt, ורק אז הכפילו בשתיים את השורש שלו.", level: "medium"},
    {q: "לוח מחומר שביר בעל E=200 GPa ו-γs=2 J/m² מכיל סדק פנימי עם a=1 מ״מ. מהו המאמץ הקריטי σc להתפשטות הסדק (לפי גריפית)?", options: ["≈1.6 MPa", "≈8.0 MPa", "≈16 MPa", "≈160 MPa"], answer: 2, explain: "σc=√(2Eγs/(πa))=√[(2×200×10⁹×2)/(π×0.001)]=√(2.546×10¹⁴)≈15.96 MPa ≈ 16 MPa.", hint: "הציבו את E ביחידות פסקל ו-a במטרים לפני החישוב.", level: "medium"},
    {q: "רכיב עשוי מחומר עם KIc=50 MPa√m ו-Y=1.0, ומכיל סדק a=2 מ״מ. מהו מאמץ העיצוב המקסימלי המותר σc?", options: ["≈50 MPa", "≈316 MPa", "≈631 MPa", "≈1000 MPa"], answer: 2, explain: "σc=KIc/(Y√(πa))=50/√(π×0.002)=50/0.0793≈631 MPa.", hint: "השתמשו במשוואה σc=KIc/(Y√(πa)) עם a במטרים.", level: "medium"},
    {q: "עבור חומר עם KIc=60 MPa√m, Y=1.2, ומאמץ שירות σ=300 MPa, מהו אורך הפגם המקסימלי המותר ac?", options: ["≈0.5 מ״מ", "≈2.8 מ״מ", "≈8.8 מ״מ", "≈17.7 מ״מ"], answer: 2, explain: "ac=(1/π)(KIc/(Yσ))²=(1/π)(60/360)²=(1/π)(0.1667)²=(1/π)(0.02778)≈0.00884 m=8.84 מ״מ.", hint: "חשבו קודם את היחס KIc/(Yσ), העלו בריבוע, ואז חלקו ב-π.", level: "medium"},
    {q: "במחזור מאמץ עם σmax=350 MPa ו-σmin=50 MPa, מהו יחס המאמצים R?", options: ["≈0.14", "≈0.43", "≈2.33", "≈7.0"], answer: 0, explain: "R=σmin/σmax=50/350≈0.143.", hint: "R הוא פשוט מינימום חלקי מקסימום.", level: "medium"},
    {q: "מוט פלדה נתון להתחממות והתקררות חוזרות בסביבה מוגבלת מכנית, עם αl=12×10⁻6/°C, E=200 GPa, ו-ΔT=150°C. מהו המאמץ התרמי המתפתח?", options: ["≈36 MPa", "≈180 MPa", "≈360 MPa", "≈600 MPa"], answer: 2, explain: "σ=αlEΔT=12×10⁻6×200,000 MPa×150=360 MPa.", hint: "המרו את E ל-MPa (200,000) לפני ההכפלה כדי לשמור על עקביות יחידות.", level: "medium"},
    {q: "מוט גלילי בקוטר d0=12 מ״מ נבדק במבחן מסתובב-כפוף עם L=50 מ״מ ומקדם ביטחון N=2, כאשר גבול העייפות של החומר הוא 250 MPa. מהו העומס המקסימלי המותר F?", options: ["≈212 N", "≈425 N", "≈848 N", "≈1696 N"], answer: 2, explain: "F=σπd0³/(16NL)=(250×10⁶×π×(0.012)³)/(16×2×0.05)=1357.2/1.6≈848 N.", hint: "d0³ קטן מאוד עבור d0 במטרים — ודאו שהכפלתם נכון לפני החלוקה.", level: "hard"},
    {q: "מהו התפקיד של המעריך n במשוואת קצב הזחילה ε̇s=K1σⁿ?", options: ["הוא תמיד שווה ל-2, כמו במשוואת גידול גרגיר", "הוא שיפוע הגרף של לוגריתם קצב הזחילה מול לוגריתם המאמץ, ומעיד על מנגנון הזחילה הדומיננטי", "הוא תלוי רק בטמפרטורה ולא במאמץ", "הוא זהה לאנרגיית האקטיבציה לזחילה Qc"], answer: 1, explain: "ערך n משתנה בין חומרים ומשתנה עם מנגנון הזחילה השולט (דיפוזיה, החלקת גבול גרגיר, תנועת נקעים וכו׳), ומזוהה משיפוע גרף log-log.", hint: "חשבו על מה קורה כששורטטים ln(קצב זחילה) מול ln(מאמץ).", level: "hard"},
    {q: "מדוע גרגיר גדול יותר עשוי להיות עדיף על גרגיר קטן עבור עמידות בזחילה בטמפרטורה גבוהה, בניגוד למגמה בטמפרטורת החדר?", options: ["כי גרגיר גדול תמיד מוליך חום טוב יותר", "כי גרגיר גדול מפחית שטח גבול גרגיר זמין להחלקת גבולות גרגיר, המאיצה זחילה", "כי משוואת הול-פץ' דורשת גרגיר גדול בטמפרטורה גבוהה", "אין הבדל אמיתי, זו טעות נפוצה בספרות"], answer: 1, explain: "בזחילה, גבולות גרגיר הם אתרי החלקה (grain boundary sliding) התורמים לעיוות; פחות שטח גבול גרגיר (גרגיר גדול) מאט זחילה, בניגוד לתפקיד גבולות הגרגיר כמחסום לנקעים בטמפרטורת החדר.", hint: "חשבו מה עושים גבולות גרגיר בזחילה, בשונה מתפקידם בחיזוק בטמפרטורת החדר.", level: "hard"},
    {q: "רכיב מ-S-590 חשוף למאמץ שבו פרמטר לארסון-מילר m=25×10³ (K·h, C=20) בטמפרטורה של 800°C (1073K). מהו אורך חיי הקריעה המשוער?", options: ["≈233 שעות", "≈500 שעות", "≈1990 שעות", "≈5000 שעות"], answer: 2, explain: "25000=1073(20+log tr) → 25000/1073=23.30=20+log tr → log tr=3.30 → tr=10^3.30≈1995 שעות (כ-1990-2000 שעות).", hint: "בודדו את log tr מהמשוואה, ואז העלו 10 בחזקת אותו ערך.", level: "hard"},
    {q: "מדוע שבר שביר מתרחש לרוב במשטח כמעט מאונך לכיוון המאמץ המופעל, ולא באלכסון 45°?", options: ["כי שבר שביר תמיד מתרחש בגזירה", "כי הוא נשלט על ידי מאמצי מתיחה נורמליים (בקיעה), לא מאמצי גזירה מקסימליים כמו בשלב הגזירה הסופי של שבר גמיש", "כי מאמצי גזירה גבוהים יותר במאונך למאמץ", "אין קשר בין כיוון השבר לסוג המאמץ"], answer: 1, explain: "שבר שביר מתקדם בבקיעה — שבירת קשרים לאורך מישורים גבישיים בתגובה למאמץ מתיחה נורמלי, ולכן מאונך (בקירוב) לכיוון המאמץ; שבר גזירה (45°) מאפיין את שלב הגזירה הסופי בשבר גמיש בלבד.", hint: "חשבו על ההבדל בין מנגנון בקיעה (מתיחה נורמלית) למנגנון גזירה.", level: "hard"},
    {q: "מדוע פלדת פחמן בינונית (1040) מדורגת ראשונה הן בקריטריון הכניעה והן בקריטריון דליפה-לפני-שבר עבור מכל לחץ כדורי (טבלאות 8.3–8.4)?", options: ["כי יש לה את חוזק הכניעה הגבוה ביותר מבין הסגסוגות שנבדקו", "כי יש לה את היחס הגבוה ביותר בין KIc לחוזק הכניעה שלה, מבין שתי הצורות (K²Ic/σy² ו-K²Ic/σy)", "כי היא הזולה ביותר מבין הסגסוגות", "כי אין לה כלל KIc מוגדר"], answer: 1, explain: "שני הקריטריונים מבוססים על יחסי KIc לחוזק הכניעה בחזקות שונות; פלדת 1040 מציגה את היחס הגבוה ביותר בשני המקרים מבין הסגסוגות שנבדקו בספר, ולכן מאפשרת אורך סדק קריטי (או לחץ מרבי) הגדול ביותר.", hint: "התמקדו ביחס בין מתיחות השבר לחוזק הכניעה, לא בערך המוחלט של אף אחד מהם בנפרד.", level: "hard"},
    {q: "מהו התפקיד המרכזי של סטריאציות בניתוח כשל עייפות?", options: ["הן מציינות את מקום התחלת הסדק בלבד", "כל סטריאציה מייצגת בקירוב את התקדמות חזית הסדק במחזור עומס בודד אחד", "הן מופיעות רק בחומרים שבריריים לגמרי", "הן זהות תמיד לסימני החוף בגודלן"], answer: 1, explain: "סטריאציות הן מיקroskopиות ומאפשרות, בספירתן, הערכה של מספר מחזורי העומס שחוותה הדגימה במהלך התפשטות הסדק.", hint: "חשבו על מה שקורה בכל מחזור עומס בודד לאורך חזית הסדק.", level: "medium"}
  ]
